import React, { useState, useContext } from 'react';
import { Link } from 'react-router-dom';
import { FaHeart, FaRegHeart, FaCommentAlt, FaBookmark, FaRegBookmark, FaShare } from 'react-icons/fa';
import { toast } from 'react-toastify';
import { AuthContext } from '../context/AuthContext';
import formatDate from '../utils/formatDate';
import forumService from '../services/forumService';

const ForumPostCard = ({ post, onPostUpdate }) => {
  const { user } = useContext(AuthContext);
  const [isLiked, setIsLiked] = useState(post.likes?.includes(user?._id));
  const [likeCount, setLikeCount] = useState(post.likes?.length || 0);
  const [isBookmarked, setIsBookmarked] = useState(post.isBookmarked);
  const [loading, setLoading] = useState(false);

  const handleLike = async (e) => {
    e.preventDefault();
    e.stopPropagation();
    
    if (!user) {
      toast.error('Please login to like posts');
      return;
    }

    try {
      setLoading(true);
      await forumService.likePost(post._id);
      const newLikedState = !isLiked;
      setIsLiked(newLikedState);
      setLikeCount(prevCount => newLikedState ? prevCount + 1 : prevCount - 1);
      if (onPostUpdate) onPostUpdate();
    } catch (error) {
      toast.error('Failed to like post');
      console.error('Like error:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleBookmark = async (e) => {
    e.preventDefault();
    e.stopPropagation();
    
    if (!user) {
      toast.error('Please login to bookmark posts');
      return;
    }

    try {
      setLoading(true);
      await forumService.bookmarkPost(post._id);
      setIsBookmarked(!isBookmarked);
      if (onPostUpdate) onPostUpdate();
    } catch (error) {
      toast.error('Failed to bookmark post');
      console.error('Bookmark error:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleShare = (e) => {
    e.preventDefault();
    e.stopPropagation();
    
    const url = `${window.location.origin}/forum/${post._id}`;
    
    if (navigator.share) {
      navigator.share({
        title: post.title,
        text: 'Check out this post on AgriConnect',
        url,
      })
      .catch(error => {
        console.error('Error sharing:', error);
        fallbackShare(url);
      });
    } else {
      fallbackShare(url);
    }
  };

  const fallbackShare = (url) => {
    navigator.clipboard.writeText(url)
      .then(() => toast.success('Link copied to clipboard!'))
      .catch(() => toast.error('Failed to copy link'));
  };

  // Truncate text if it's too long
  const truncateText = (text, maxLength = 150) => {
    if (!text) return '';
    return text.length > maxLength ? text.substring(0, maxLength) + '...' : text;
  };

  return (
    <div className="bg-white rounded-lg shadow-md overflow-hidden hover:shadow-lg transition duration-300">
      <Link to={`/forum/${post._id}`} className="block">
        <div className="p-4">
          <div className="flex items-center mb-3">
            <img 
              src={post.author?.profilePicture || 'https://via.placeholder.com/40'} 
              alt={post.author?.name} 
              className="w-10 h-10 rounded-full mr-3"
            />
            <div>
              <p className="font-medium text-gray-800">{post.author?.name || 'Anonymous'}</p>
              <p className="text-xs text-gray-500">{formatDate(post.createdAt)}</p>
            </div>
          </div>
          
          <h3 className="text-xl font-semibold text-gray-800 mb-2">{post.title}</h3>
          <p className="text-gray-700 mb-4">{truncateText(post.content)}</p>
          
          {post.image && (
            <div className="mb-4">
              <img 
                src={post.image} 
                alt={post.title} 
                className="w-full h-48 object-cover rounded"
              />
            </div>
          )}
          
          <div className="flex items-center justify-between mt-4 pt-3 border-t border-gray-100">
            <div className="flex items-center space-x-4">
              <button 
                onClick={handleLike} 
                className={`flex items-center ${isLiked ? 'text-red-500' : 'text-gray-500'} hover:text-red-500 transition`}
                disabled={loading}
              >
                {isLiked ? <FaHeart /> : <FaRegHeart />}
                <span className="ml-1">{likeCount}</span>
              </button>
              
              <div className="flex items-center text-gray-500">
                <FaCommentAlt />
                <span className="ml-1">{post.comments?.length || 0}</span>
              </div>
            </div>
            
            <div className="flex space-x-3">
              <button 
                onClick={handleBookmark} 
                className={`${isBookmarked ? 'text-blue-500' : 'text-gray-500'} hover:text-blue-500 transition`}
                disabled={loading}
              >
                {isBookmarked ? <FaBookmark /> : <FaRegBookmark />}
              </button>
              
              <button 
                onClick={handleShare} 
                className="text-gray-500 hover:text-green-500 transition"
              >
                <FaShare />
              </button>
            </div>
          </div>
        </div>
      </Link>
    </div>
  );
};

export default ForumPostCard;
